namespace RecipeSharingApp.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

namespace RecipeSharingApp.Models;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple yet delicious traditional Italian pizza.",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = [
                    "Preheat oven to 475°F (245°C) with a pizza stone inside.",
                    "Stretch dough into a 12-inch circle on a floured surface.",
                    "Spread crushed tomatoes evenly over the dough.",
                    "Tear mozzarella into pieces and distribute over the sauce.",
                    "Bake for 10-12 minutes until crust is golden and cheese is bubbly.",
                    "Top with fresh basil leaves and a drizzle of olive oil."
                ],
                TotalRatings = 12, RatingSum = 52
            },
            new Recipe
            {
                Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken in a creamy, spiced tomato sauce.",
                Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger", "Cilantro"],
                Steps = [
                    "Marinate chicken in yogurt and spices for at least 1 hour.",
                    "Grill or broil chicken until slightly charred, then cube.",
                    "Sauté onion, garlic, and ginger until softened.",
                    "Add tomato sauce and spices, simmer for 15 minutes.",
                    "Stir in cream and cooked chicken, simmer 10 more minutes.",
                    "Garnish with cilantro and serve with basmati rice."
                ],
                TotalRatings = 8, RatingSum = 38
            },
            new Recipe
            {
                Id = 3, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "A rich Roman pasta dish with eggs, cheese, and pancetta.",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper"],
                Steps = [
                    "Cook spaghetti in salted boiling water until al dente.",
                    "Crisp pancetta in a skillet over medium heat.",
                    "Whisk eggs with grated Pecorino and plenty of black pepper.",
                    "Toss hot pasta with pancetta and remove from heat.",
                    "Quickly stir in the egg mixture, tossing constantly to coat.",
                    "Serve immediately with extra cheese and pepper."
                ],
                TotalRatings = 15, RatingSum = 68
            },
            new Recipe
            {
                Id = 4, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef tacos with fresh toppings.",
                Ingredients = ["Ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = [
                    "Brown ground beef in a skillet and drain excess fat.",
                    "Add taco seasoning and water, simmer until thickened.",
                    "Warm tortillas in a dry skillet or microwave.",
                    "Fill tortillas with seasoned beef.",
                    "Top with shredded lettuce, diced tomato, cheese, sour cream, and salsa."
                ],
                TotalRatings = 6, RatingSum = 25
            },
            new Recipe
            {
                Id = 5, Title = "Pad Thai", Category = "Thai",
                Description = "A classic Thai stir-fried noodle dish.",
                Ingredients = ["Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Green onions", "Peanuts", "Tamarind paste", "Fish sauce", "Lime"],
                Steps = [
                    "Soak rice noodles in warm water for 30 minutes, then drain.",
                    "Make sauce by mixing tamarind paste, fish sauce, and sugar.",
                    "Stir-fry shrimp until pink, push to the side, scramble eggs.",
                    "Add noodles and sauce, toss until noodles are tender.",
                    "Add bean sprouts and green onions, toss briefly.",
                    "Serve topped with crushed peanuts and lime wedges."
                ],
                TotalRatings = 10, RatingSum = 44
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh and creamy avocado dip.",
                Ingredients = ["Avocados", "Lime juice", "Red onion", "Cilantro", "Jalapeño", "Tomato", "Salt"],
                Steps = [
                    "Halve avocados and remove pits.",
                    "Mash avocado flesh in a bowl to desired consistency.",
                    "Stir in finely diced onion, jalapeño, and tomato.",
                    "Add lime juice, chopped cilantro, and salt to taste.",
                    "Serve immediately with tortilla chips."
                ],
                TotalRatings = 9, RatingSum = 40
            },
            new Recipe
            {
                Id = 7, Title = "Miso Soup", Category = "Japanese",
                Description = "A light and savory traditional Japanese soup.",
                Ingredients = ["Dashi stock", "Miso paste", "Tofu", "Wakame seaweed", "Green onions"],
                Steps = [
                    "Bring dashi stock to a gentle simmer.",
                    "Rehydrate wakame in water, then drain.",
                    "Cube tofu into small pieces.",
                    "Dissolve miso paste in a ladleful of hot dashi, then stir back into the pot.",
                    "Add tofu and wakame, heat without boiling.",
                    "Serve garnished with sliced green onions."
                ],
                TotalRatings = 7, RatingSum = 30
            },
            new Recipe
            {
                Id = 8, Title = "Chocolate Lava Cake", Category = "Desserts",
                Description = "Individual cakes with a molten chocolate center.",
                Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
                Steps = [
                    "Preheat oven to 425°F (220°C). Grease ramekins and dust with cocoa.",
                    "Melt chocolate and butter together, then let cool slightly.",
                    "Whisk eggs, sugar, and vanilla until thick and pale.",
                    "Fold chocolate mixture into the eggs, then fold in flour.",
                    "Divide batter among ramekins and bake for 12-14 minutes.",
                    "Let stand 1 minute, then invert onto plates. Serve immediately."
                ],
                TotalRatings = 20, RatingSum = 95
            }
        ];
        _nextId = 9;
    }

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public Recipe AddRecipe(RecipeSubmission submission)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Description = $"A community-submitted {submission.Category.ToLowerInvariant()} recipe.",
            Ingredients = submission.Ingredients
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = submission.Steps
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

