arguments.file_text:
@page "/category/{CategoryName}"
@using RecipeSharingApp.Models
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <div class="mb-2">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                                }
                            </span>
                            <small class="text-muted">(@recipe.TotalRatings ratings)</small>
                        </div>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    private List<Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeSharingApp.Models
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>

    <StarRating RecipeId="recipe.Id" CurrentAverage="recipe.AverageRating" TotalRatings="recipe.TotalRatings" />

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><h4 class="mb-0">Ingredients</h4></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h4>Instructions</h4>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeSharingApp.Models
@inject RecipeService RecipeService

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              class="fs-4 @(star <= (userRating ?? (int)Math.Round(CurrentAverage)) ? "text-warning" : "text-muted")"
              style="cursor: pointer;"
              @onclick="() => Rate(star)"
              @onmouseover="() => hoverStar = star"
              @onmouseout="() => hoverStar = null">
            @(star <= (hoverStar ?? userRating ?? (int)Math.Round(CurrentAverage)) ? "★" : "☆")
        </span>
    }
    <span class="ms-2 text-muted">
        @if (userRating.HasValue)
        {
            <text>You rated @userRating stars!</text>
        }
        else
        {
            <text>@CurrentAverage.ToString("0.0") avg (@TotalRatings ratings)</text>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int? userRating;
    private int? hoverStar;

    private void Rate(int stars)
    {
        if (userRating.HasValue) return;
        userRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            TotalRatings = recipe.TotalRatings;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeSharingApp.Models
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted!</h4>
        <p>Your recipe "<strong>@submission.Title</strong>" has been added.</p>
        <a href="recipe/@newRecipeId" class="btn btn-primary">View Your Recipe</a>
    </div>
}
else
{
    <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" class="form-control" @bind-Value="submission.Title" placeholder="e.g., Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" class="form-select" @bind-Value="submission.Category">
                        <option value="">-- Select a category --</option>
                        @foreach (var cat in RecipeService.GetCategories())
                        {
                            <option value="@cat">@cat</option>
                        }
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients</label>
                    <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="submission.Ingredients"
                                   placeholder="Enter one ingredient per line&#10;e.g.,&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
                    <div class="form-text">Enter one ingredient per line.</div>
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Preparation Steps</label>
                    <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="submission.Steps"
                                   placeholder="Enter one step per line&#10;e.g.,&#10;Preheat oven to 350°F&#10;Mix dry ingredients together&#10;Add wet ingredients and stir" />
                    <div class="form-text">Enter one step per line.</div>
                </div>

                @if (!string.IsNullOrEmpty(errorMessage))
                {
                    <div class="alert alert-danger">@errorMessage</div>
                }

                <button type="submit" class="btn btn-success btn-lg">Submit Recipe</button>
            </div>
        </div>
    </EditForm>
}

@code {
    private RecipeSubmission submission = new();
    private bool submitted;
    private int newRecipeId;
    private string? errorMessage;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(submission.Title) ||
            string.IsNullOrWhiteSpace(submission.Category) ||
            string.IsNullOrWhiteSpace(submission.Ingredients) ||
            string.IsNullOrWhiteSpace(submission.Steps))
        {
            errorMessage = "Please fill in all fields.";
            return;
        }

        var recipe = RecipeService.AddRecipe(submission);
        newRecipeId = recipe.Id;
        submitted = true;
    }
}

@page "/category/{CategoryName}"
@using RecipeSharingApp.Models
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text">@recipe.Description</p>
                        <div class="mb-2">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                                }
                            </span>
                            <small class="text-muted">(@recipe.TotalRatings ratings)</small>
                        </div>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    private List<Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeSharingApp.Models
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe")</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead">@recipe.Description</p>

    <StarRating RecipeId="recipe.Id" CurrentAverage="recipe.AverageRating" TotalRatings="recipe.TotalRatings" />

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><h4 class="mb-0">Ingredients</h4></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h4>Instructions</h4>
            <ol class="list-group list-group-numbered mb-4">
                @foreach (var step in recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }
    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeSharingApp.Models
@inject RecipeService RecipeService

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              class="fs-4 @(star <= (userRating ?? (int)Math.Round(CurrentAverage)) ? "text-warning" : "text-muted")"
              style="cursor: pointer;"
              @onclick="() => Rate(star)"
              @onmouseover="() => hoverStar = star"
              @onmouseout="() => hoverStar = null">
            @(star <= (hoverStar ?? userRating ?? (int)Math.Round(CurrentAverage)) ? "★" : "☆")
        </span>
    }
    <span class="ms-2 text-muted">
        @if (userRating.HasValue)
        {
            <text>You rated @userRating stars!</text>
        }
        else
        {
            <text>@CurrentAverage.ToString("0.0") avg (@TotalRatings ratings)</text>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int? userRating;
    private int? hoverStar;

    private void Rate(int stars)
    {
        if (userRating.HasValue) return;
        userRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            TotalRatings = recipe.TotalRatings;
        }
    }
}

