toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@using RecipeSharingApp.Models
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted!</h4>
        <p>Your recipe "<strong>@submission.Title</strong>" has been added.</p>
        <a href="recipe/@newRecipeId" class="btn btn-primary">View Your Recipe</a>
    </div>
}
else
{
    <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label for="title" class="form-label">Recipe Title</label>
                    <InputText id="title" class="form-control" @bind-Value="submission.Title" placeholder="e.g., Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label for="category" class="form-label">Category</label>
                    <InputSelect id="category" class="form-select" @bind-Value="submission.Category">
                        <option value="">-- Select a category --</option>
                        @foreach (var cat in RecipeService.GetCategories())
                        {
                            <option value="@cat">@cat</option>
                        }
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label for="ingredients" class="form-label">Ingredients</label>
                    <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="submission.Ingredients"
                                   placeholder="Enter one ingredient per line&#10;e.g.,&#10;2 cups flour&#10;1 cup sugar&#10;3 eggs" />
                    <div class="form-text">Enter one ingredient per line.</div>
                </div>

                <div class="mb-3">
                    <label for="steps" class="form-label">Preparation Steps</label>
                    <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="submission.Steps"
                                   placeholder="Enter one step per line&#10;e.g.,&#10;Preheat oven to 350°F&#10;Mix dry ingredients together&#10;Add wet ingredients and stir" />
                    <div class="form-text">Enter one step per line.</div>
                </div>

                @if (!string.IsNullOrEmpty(errorMessage))
                {
                    <div class="alert alert-danger">@errorMessage</div>
                }

                <button type="submit" class="btn btn-success btn-lg">Submit Recipe</button>
            </div>
        </div>
    </EditForm>
}

@code {
    private RecipeSubmission submission = new();
    private bool submitted;
    private int newRecipeId;
    private string? errorMessage;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(submission.Title) ||
            string.IsNullOrWhiteSpace(submission.Category) ||
            string.IsNullOrWhiteSpace(submission.Ingredients) ||
            string.IsNullOrWhiteSpace(submission.Steps))
        {
            errorMessage = "Please fill in all fields.";
            return;
        }

        var recipe = RecipeService.AddRecipe(submission);
        newRecipeId = recipe.Id;
        submitted = true;
    }
}

